"use strict";(self.webpackChunkfedpat_docs=self.webpackChunkfedpat_docs||[]).push([[8603],{342:(e,n,r)=>{r.r(n),r.d(n,{assets:()=>c,contentTitle:()=>t,default:()=>d,frontMatter:()=>o,metadata:()=>a,toc:()=>l});var s=r(4848),i=r(8453);const o={id:"netcore-skill-raw",title:"SKILL.md \u2014 NetCore",sidebar_label:"SKILL.md"},t="SKILL.md \u2014 NetCore",a={id:"ia/claude-skills/netcore-skill-raw",title:"SKILL.md \u2014 NetCore",description:"Archivo de instrucciones que Claude usa internamente. Si encontr\xe1s algo para mejorar, abr\xed un PR directamente.",source:"@site/docs/ia/claude-skills/netcore-skill-raw.md",sourceDirName:"ia/claude-skills",slug:"/ia/claude-skills/netcore-skill-raw",permalink:"/flock-tech-guides/ia/claude-skills/netcore-skill-raw",draft:!1,unlisted:!1,editUrl:"https://github.com/Mujics/flock-tech-guides/tree/main/flock-tech-guides/docs/ia/claude-skills/netcore-skill-raw.md",tags:[],version:"current",frontMatter:{id:"netcore-skill-raw",title:"SKILL.md \u2014 NetCore",sidebar_label:"SKILL.md"},sidebar:"docs",previous:{title:"NetCore Skill",permalink:"/flock-tech-guides/ia/claude-skills/netcore-skill"},next:{title:"Python Skill",permalink:"/flock-tech-guides/ia/claude-skills/python-skill"}},c={},l=[];function u(e){const n={a:"a",admonition:"admonition",code:"code",h1:"h1",hr:"hr",p:"p",pre:"pre",...(0,i.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(n.h1,{id:"skillmd--netcore",children:"SKILL.md \u2014 NetCore"}),"\n",(0,s.jsx)(n.p,{children:"Archivo de instrucciones que Claude usa internamente. Si encontr\xe1s algo para mejorar, abr\xed un PR directamente."}),"\n",(0,s.jsx)(n.admonition,{title:"Contribuir",type:"info",children:(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.a,{href:"https://github.com/Flock-engineering/flock-tech-guides/edit/dev/static/skills/netcore/SKILL.md",children:"\u270f\ufe0f Sugerir correcci\xf3n en GitHub"})," \u2014 GitHub te propone hacer fork y PR autom\xe1ticamente si no ten\xe9s permisos de push."]})}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.a,{href:"pathname:///flock-tech-guides/skills/netcore/SKILL.md",children:"\u2b07 Descargar SKILL.md"})}),"\n",(0,s.jsx)(n.hr,{}),"\n",(0,s.jsx)(n.pre,{children:(0,s.jsx)(n.code,{className:"language-md",children:'---\nname: netcore\ndescription: >\n  .NET/C# moderno con calidad de c\xf3digo, primary constructors, null safety y patrones idiom\xe1ticos.\n  Trigger: crear clase C#, crear servicio .NET, refactorizar C#, mejorar calidad .NET, escribir c\xf3digo NetCore\nlicense: MIT\nmetadata:\n  author: tu-proyecto\n  version: \'1.0\'\n  scope: [root]\n  auto_invoke:\n    - \'Crear clase C#\'\n    - \'Crear servicio .NET\'\n    - \'Refactorizar C#\'\n    - \'Mejorar calidad .NET\'\n    - \'Escribir c\xf3digo NetCore\'\n    - \'Crear controller\'\n    - \'Crear endpoint\'\nallowed-tools: Read, Edit, Write, Glob, Grep, Bash\n---\n\n# NetCore Skill\n\n## Critical Rules\n\n### ALWAYS\n\n- Usar **primary constructors** (C# 12) para inyecci\xf3n de dependencias \u2014 sin campos privados repetitivos\n- Usar **`ILogger<T>`** v\xeda inyecci\xf3n por constructor \u2014 nunca `Console.WriteLine` en producci\xf3n\n- Usar **`record`** para DTOs inmutables \u2014 conciso, con equals/hashCode/toString autom\xe1ticos\n- Habilitar **nullable reference types** (`#nullable enable`) \u2014 eliminar null bugs silenciosos\n- Usar **`ArgumentNullException.ThrowIfNull`** para guardar cl\xe1usulas de par\xe1metros\n- Aplicar Single Responsibility: clases < 200 l\xedneas, m\xe9todos < 20 l\xedneas\n- Usar **LINQ** para procesar colecciones en vez de loops imperativos\n- Usar **pattern matching** con `is`, `switch` expressions y `when` guards (C# 8+)\n- Usar **`async/await`** correctamente \u2014 nunca `.Result` ni `.Wait()` en async contexts\n- Definir **jerarqu\xeda de excepciones propia** \u2014 nunca `catch (Exception e)` silencioso\n- Extraer constantes nombradas \u2014 sin magic numbers ni magic strings en la l\xf3gica\n- Usar generics para evitar duplicaci\xf3n: `PaginatedResponse<T>`, `Result<T>`\n- Preferir composici\xf3n sobre herencia\n\n### NEVER\n\n- Usar `Console.WriteLine` para logging en producci\xf3n \u2014 usar `ILogger<T>`\n- Usar `Thread.Sleep` \u2014 usar `await Task.Delay`\n- Usar `.Result` o `.Wait()` en contextos async \u2014 causa deadlocks\n- Retornar `null` desde m\xe9todos que prometen un objeto \u2014 lanzar excepci\xf3n o usar `Result<T>`\n- Capturar `Exception` con catch vac\xedo o solo con `Console.WriteLine`\n- Crear clases con m\xe1s de una responsabilidad (God classes)\n- Usar estado mutable est\xe1tico sin thread-safety\n- Duplicar l\xf3gica entre clases \u2014 extraer a base, interfaz o utility\n- Usar `var` para tipos no obvios \u2014 preferir tipo expl\xedcito cuando mejora legibilidad\n\n---\n\n## Primary Constructors \u2014 Inyecci\xf3n sin Boilerplate (C# 12)\n\n```csharp\n// \u274c MAL \u2014 boilerplate repetitivo con campo privado\npublic class UserService\n{\n    private readonly IUserRepository _userRepository;\n    private readonly ILogger<UserService> _logger;\n\n    public UserService(IUserRepository userRepository, ILogger<UserService> logger)\n    {\n        _userRepository = userRepository;\n        _logger = logger;\n    }\n}\n\n// \u2705 BIEN \u2014 primary constructor elimina el boilerplate\npublic class UserService(IUserRepository userRepository, ILogger<UserService> logger)\n{\n    public async Task<UserResponse> GetByIdAsync(int id)\n    {\n        var user = await userRepository.GetByIdAsync(id)\n            ?? throw new EntityNotFoundException(nameof(User), id);\n        logger.LogInformation("User retrieved id={Id}", id);\n        return UserResponse.From(user);\n    }\n}\n```\n\n---\n\n## ILogger<T> \u2014 Logging Estructurado\n\n```csharp\n// \u274c MAL \u2014 Console.WriteLine (no structured, no levels, no sink)\nConsole.WriteLine($"User created: {user.Id}");\n\n// \u2705 BIEN \u2014 ILogger<T> con message templates estructurados\npublic class UserService(ILogger<UserService> logger)\n{\n    public async Task<UserResponse> CreateAsync(CreateUserRequest request)\n    {\n        logger.LogInformation("Creating user email={Email}", request.Email);\n\n        // ... l\xf3gica\n\n        logger.LogInformation("User created id={Id} email={Email}", user.Id, user.Email);\n        return UserResponse.From(user);\n    }\n}\n\n// Niveles de log:\nlogger.LogDebug("Debug info: {Data}", data);\nlogger.LogInformation("User {Id} logged in", userId);\nlogger.LogWarning("Retry attempt {Attempt} for {Operation}", attempt, operation);\nlogger.LogError(ex, "Failed to process order {OrderId}", orderId);\nlogger.LogCritical("Database connection lost");\n```\n\n---\n\n## Record \u2014 DTO Inmutable\n\n```csharp\n// \u2705 BIEN \u2014 record es conciso, inmutable y genera equals/hashCode/toString\npublic record CreateUserRequest(\n    [Required] string Name,\n    [EmailAddress] string Email,\n    UserRole Role\n);\n\npublic record UserResponse(int Id, string Name, string Email, UserRole Role)\n{\n    public static UserResponse From(User user) =>\n        new(user.Id, user.Name, user.Email, user.Role);\n}\n\n// Record con validaci\xf3n adicional:\npublic record PaginationRequest(int Page = 1, int PageSize = 20)\n{\n    public int Page { get; init; } = Page > 0 ? Page : 1;\n    public int PageSize { get; init; } = PageSize is > 0 and <= 100 ? PageSize : 20;\n}\n```\n\n---\n\n## Nullable Reference Types \u2014 Null Safety\n\n```csharp\n// Habilitar en el proyecto completo (en .csproj):\n// <Nullable>enable</Nullable>\n\n// O en el archivo:\n#nullable enable\n\n// \u274c MAL \u2014 null impl\xedcito que el compilador no detecta\npublic User GetById(int id) => _repo.FindById(id); // puede retornar null\n\n// \u2705 BIEN \u2014 null expl\xedcito con ? o lanzar excepci\xf3n\npublic User? FindById(int id) => _repo.FindById(id); // puede ser null\npublic User GetById(int id) =>                        // nunca null\n    _repo.FindById(id) ?? throw new EntityNotFoundException(nameof(User), id);\n\n// ArgumentNullException.ThrowIfNull \u2014 guard clause idiom\xe1tica\npublic void Process(Order order)\n{\n    ArgumentNullException.ThrowIfNull(order);\n    ArgumentNullException.ThrowIfNull(order.Items, nameof(order.Items));\n    // l\xf3gica principal sin anidaci\xf3n\n}\n```\n\n---\n\n## LINQ \u2014 Colecciones sin Loops Imperativos\n\n```csharp\n// \u274c MAL \u2014 loop imperativo\nvar activeEmails = new List<string>();\nforeach (var user in users)\n{\n    if (user.IsActive)\n        activeEmails.Add(user.Email.ToLower());\n}\n\n// \u2705 BIEN \u2014 LINQ declarativo\nvar activeEmails = users\n    .Where(u => u.IsActive)\n    .Select(u => u.Email.ToLower())\n    .ToList();\n\n// Agrupar:\nvar byRole = users.GroupBy(u => u.Role)\n                  .ToDictionary(g => g.Key, g => g.ToList());\n\n// Proyecci\xf3n con tipo an\xf3nimo o record:\nvar summary = users\n    .Where(u => u.IsActive)\n    .Select(u => new { u.Id, u.Email, u.Role })\n    .ToList();\n\n// Primer elemento o excepci\xf3n:\nvar admin = users.FirstOrDefault(u => u.Role == UserRole.Admin)\n    ?? throw new EntityNotFoundException("Admin user not found");\n\n// Any / All:\nbool hasAdmins = users.Any(u => u.Role == UserRole.Admin);\nbool allActive = users.All(u => u.IsActive);\n```\n\n---\n\n## Pattern Matching \u2014 Sin Casteos (C# 8+)\n\n```csharp\n// \u274c MAL \u2014 casteo expl\xedcito\nif (shape is Circle) { var c = (Circle)shape; Console.WriteLine(c.Radius); }\n\n// \u2705 BIEN \u2014 pattern matching con is\nif (shape is Circle circle) { logger.LogInformation("Radio: {R}", circle.Radius); }\n\n// \u2705 MEJOR \u2014 switch expression con pattern matching (C# 8+)\nstring description = shape switch\n{\n    Circle    c when c.Radius > 10 => $"C\xedrculo grande (r={c.Radius})",\n    Circle    c                    => $"C\xedrculo peque\xf1o (r={c.Radius})",\n    Rectangle { Width: var w, Height: var h } => $"Rect\xe1ngulo {w}x{h}",\n    _                              => "Forma desconocida"\n};\n\n// Deconstruct pattern en if:\nif (result is Result<User>.Success { Value: var user })\n{\n    return UserResponse.From(user);\n}\n```\n\n---\n\n## Service Pattern (ASP.NET Core + primary constructor)\n\n```csharp\npublic class UserService(\n    IUserRepository userRepository,\n    ILogger<UserService> logger)\n{\n    public async Task<UserResponse> GetByIdAsync(int id)\n    {\n        var user = await userRepository.GetByIdAsync(id)\n            ?? throw new EntityNotFoundException(nameof(User), id);\n        return UserResponse.From(user);\n    }\n\n    public async Task<UserResponse> CreateAsync(CreateUserRequest request)\n    {\n        ArgumentNullException.ThrowIfNull(request);\n\n        if (await userRepository.ExistsByEmailAsync(request.Email))\n            throw new ConflictException($"Email {request.Email} already in use", "EMAIL_CONFLICT");\n\n        var user = new User { Name = request.Name, Email = request.Email, Role = request.Role };\n        await userRepository.AddAsync(user);\n\n        logger.LogInformation("User created id={Id} email={Email}", user.Id, user.Email);\n        return UserResponse.From(user);\n    }\n\n    public async Task<UserResponse> UpdateAsync(int id, UpdateUserRequest request)\n    {\n        ArgumentNullException.ThrowIfNull(request);\n\n        var user = await userRepository.GetByIdAsync(id)\n            ?? throw new EntityNotFoundException(nameof(User), id);\n\n        user.Name  = request.Name;\n        user.Email = request.Email;\n        await userRepository.UpdateAsync(user);\n\n        logger.LogInformation("User updated id={Id}", id);\n        return UserResponse.From(user);\n    }\n}\n```\n\n---\n\n## Exception Hierarchy \u2014 Sin Capturar Gen\xe9ricos\n\n```csharp\n// Jerarqu\xeda propia \u2014 evita lanzar/capturar Exception gen\xe9rico\npublic abstract class DomainException(string message, string code) : Exception(message)\n{\n    public string Code { get; } = code;\n}\n\npublic class EntityNotFoundException(string entity, object id)\n    : DomainException($"{entity} with id {id} not found", $"{entity.ToUpper()}_NOT_FOUND");\n\npublic class ConflictException(string message, string code) : DomainException(message, code);\n\npublic class ValidationException(string message) : DomainException(message, "VALIDATION_ERROR");\n\n// \u274c MAL\ntry { RiskyOperation(); } catch (Exception e) { Console.WriteLine(e); }\n\n// \u2705 BIEN\ntry\n{\n    await RiskyOperationAsync();\n}\ncatch (SpecificException ex)\n{\n    logger.LogError(ex, "Error procesando operaci\xf3n: {Message}", ex.Message);\n    throw new DomainException("Error en operaci\xf3n X", "OP_X_ERROR");\n}\n```\n\n---\n\n## Guard Clauses \u2014 Inputs al Inicio\n\n```csharp\n// \u274c MAL \u2014 l\xf3gica principal enterrada en niveles de if anidados\npublic void ProcessOrder(Order order)\n{\n    if (order != null)\n    {\n        if (order.Items != null && order.Items.Any())\n        {\n            if (order.Total > 0) { /* l\xf3gica */ }\n        }\n    }\n}\n\n// \u2705 BIEN \u2014 fail fast con guard clauses\npublic void ProcessOrder(Order order)\n{\n    ArgumentNullException.ThrowIfNull(order);\n\n    if (!order.Items.Any())\n        throw new ValidationException("Order must have at least one item");\n\n    if (order.Total <= 0)\n        throw new ValidationException("Order total must be positive");\n\n    // l\xf3gica principal sin anidaci\xf3n\n}\n```\n\n---\n\n## Generics \u2014 Sin Duplicaci\xf3n\n\n### Respuesta paginada gen\xe9rica\n\n```csharp\n// \u2705 Una sola definici\xf3n \u2014 usada en todos los m\xf3dulos\npublic record PaginatedResponse<T>(\n    IReadOnlyList<T> Items,\n    int Page,\n    int PageSize,\n    int TotalCount)\n{\n    public int TotalPages => (int)Math.Ceiling(TotalCount / (double)PageSize);\n    public bool HasNextPage => Page < TotalPages;\n    public bool HasPreviousPage => Page > 1;\n\n    public static PaginatedResponse<T> From(IEnumerable<T> source, int page, int pageSize, int totalCount) =>\n        new(source.ToList().AsReadOnly(), page, pageSize, totalCount);\n}\n```\n\n### Resultado gen\xe9rico (Success / Failure)\n\n```csharp\n// Discriminated union type-safe\npublic abstract record Result<T>\n{\n    public sealed record Success(T Value) : Result<T>;\n    public sealed record Failure(string Message, string Code) : Result<T>;\n\n    public static Result<T> Ok(T value)                         => new Success(value);\n    public static Result<T> Fail(string message, string code)   => new Failure(message, code);\n\n    public bool IsSuccess => this is Success;\n}\n\n// Uso con pattern matching:\nvar result = await userService.TryCreateAsync(request);\nreturn result switch\n{\n    Result<User>.Success s => Ok(UserResponse.From(s.Value)),\n    Result<User>.Failure f => BadRequest(new { f.Message, f.Code }),\n    _ => throw new UnreachableException()\n};\n```\n\n---\n\n## Async/Await \u2014 Sin Deadlocks\n\n```csharp\n// \u274c MAL \u2014 .Result y .Wait() causan deadlocks en ASP.NET Core\nvar user = userRepository.GetByIdAsync(id).Result;\nuserRepository.SaveAsync(user).Wait();\n\n// \u2705 BIEN \u2014 propagar async hasta el controller\npublic async Task<UserResponse> GetByIdAsync(int id)\n{\n    var user = await userRepository.GetByIdAsync(id)\n        ?? throw new EntityNotFoundException(nameof(User), id);\n    return UserResponse.From(user);\n}\n\n// ConfigureAwait(false) \u2014 en librer\xedas (no en ASP.NET Core controllers)\nvar data = await httpClient.GetStringAsync(url).ConfigureAwait(false);\n\n// Paralelo cuando no hay dependencias:\nvar (users, roles) = await (\n    userRepository.GetAllAsync(),\n    roleRepository.GetAllAsync()\n).WhenAll();\n\n// Cancelation token \u2014 propagar siempre\npublic async Task<List<User>> SearchAsync(string query, CancellationToken ct = default)\n{\n    return await userRepository.SearchAsync(query, ct);\n}\n```\n\n---\n\n## Commands\n\n```bash\n# Crear proyecto\ndotnet new webapi -n MyProject\n\n# Compilar\ndotnet build\n\n# Tests\ndotnet test\n\n# Tests con cobertura\ndotnet test --collect:"XPlat Code Coverage"\n\n# An\xe1lisis est\xe1tico (Roslyn Analyzers \u2014 incluidos en .NET 5+)\ndotnet build /p:TreatWarningsAsErrors=true\n\n# Linter / formato\ndotnet format\n\n# Ejecutar aplicaci\xf3n\ndotnet run\n\n# Publicar\ndotnet publish -c Release -o ./publish\n\n# Migrations (EF Core)\ndotnet ef migrations add NombreMigracion\ndotnet ef database update\n```\n\n---\n\n## Project-Specific Notes\n\nAdapt\xe1 esta secci\xf3n a las convenciones de tu proyecto:\n\n- **Versi\xf3n**: .NET 8+ (LTS recomendado) o .NET 9+\n- **Framework**: ASP.NET Core Web API / Minimal APIs / gRPC\n- **ORM**: Entity Framework Core / Dapper / NHibernate\n- **Testing**: xUnit + Moq + FluentAssertions\n- **Nullable**: habilitar `<Nullable>enable</Nullable>` en el `.csproj`\n- **Primary constructors**: disponibles desde C# 12 (.NET 8+)\n- **Analyzers incluidos**: Microsoft.CodeAnalysis.NetAnalyzers (incluido en .NET 5+)\n\n### Paquetes NuGet recomendados\n\n```xml\n\x3c!-- Testing --\x3e\n<PackageReference Include="xunit" Version="2.9.*" />\n<PackageReference Include="Moq" Version="4.20.*" />\n<PackageReference Include="FluentAssertions" Version="6.12.*" />\n\n\x3c!-- EF Core --\x3e\n<PackageReference Include="Microsoft.EntityFrameworkCore" Version="8.*" />\n<PackageReference Include="Microsoft.EntityFrameworkCore.SqlServer" Version="8.*" />\n\n\x3c!-- Validaci\xf3n --\x3e\n<PackageReference Include="FluentValidation.AspNetCore" Version="11.*" />\n\n\x3c!-- Logging estructurado (opcional \u2014 Serilog) --\x3e\n<PackageReference Include="Serilog.AspNetCore" Version="8.*" />\n```\n'})})]})}function d(e={}){const{wrapper:n}={...(0,i.R)(),...e.components};return n?(0,s.jsx)(n,{...e,children:(0,s.jsx)(u,{...e})}):u(e)}},8453:(e,n,r)=>{r.d(n,{R:()=>t,x:()=>a});var s=r(6540);const i={},o=s.createContext(i);function t(e){const n=s.useContext(o);return s.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function a(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:t(e.components),s.createElement(o.Provider,{value:n},e.children)}}}]);